import { formatPlayerName } from './task02';

describe('formatPlayerName', () => {
  it('reformats LastName, FirstName', () => {
    expect(formatPlayerName('Smith, John')).toBe('John Smith');
  });

  it('returns as-is when no comma', () => {
    expect(formatPlayerName('John Smith')).toBe('John Smith');
  });

  it('handles empty input', () => {
    expect(formatPlayerName('')).toBe('');
  });
});
